css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: #1a0a0a; font-family: -apple-system, BlinkMacSystemFont, sans-serif; display: flex; align-items: center; justify-content: center; color: white; }
.app { text-align: center; padding: 40px; }
h1 { font-size: 32px; font-weight: 900; margin-bottom: 28px; }
.mode-tabs { display: flex; gap: 8px; justify-content: center; margin-bottom: 36px; background: rgba(255,255,255,0.06); padding: 6px; border-radius: 16px; display: inline-flex; }
.tab { padding: 10px 20px; border-radius: 12px; border: none; background: transparent; color: rgba(255,255,255,0.5); font-size: 14px; font-weight: 600; cursor: pointer; transition: all 0.2s; } .tab.active { background: #ef4444; color: white; }
.timer-wrap { position: relative; width: 260px; height: 260px; margin: 0 auto 32px; }
.progress-ring { transform: rotate(-90deg); }
.ring-bg { fill: none; stroke: rgba(255,255,255,0.08); stroke-width: 10; }
.ring-fill { fill: none; stroke: #ef4444; stroke-width: 10; stroke-linecap: round; stroke-dasharray: 691; transition: stroke-dashoffset 1s linear; }
.timer-display { position: absolute; top: 50%; left: 50%; transform: translate(-50%,-50%); }
.timer-time { font-size: 56px; font-weight: 200; letter-spacing: -2px; }
.timer-label { font-size: 14px; color: rgba(255,255,255,0.5); margin-top: 4px; }
.controls { display: flex; align-items: center; justify-content: center; gap: 20px; margin-bottom: 24px; }
.ctrl-btn { width: 52px; height: 52px; border-radius: 50%; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.06); color: white; font-size: 20px; cursor: pointer; transition: all 0.2s; } .ctrl-btn:hover { background: rgba(255,255,255,0.12); }
.start-btn { width: 120px; height: 52px; border-radius: 26px; border: none; background: #ef4444; color: white; font-size: 17px; font-weight: 800; cursor: pointer; transition: all 0.2s; box-shadow: 0 8px 24px rgba(239,68,68,0.35); } .start-btn:hover { transform: scale(1.05); }
.sessions { color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 16px; }
.session-dots { display: flex; gap: 10px; justify-content: center; }
.dot { width: 12px; height: 12px; border-radius: 50%; background: rgba(255,255,255,0.15); transition: background 0.3s; } .dot.done { background: #ef4444; }

js:
const modes = { pomodoro: { time: 25*60, label: 'Odaklan!', color: '#ef4444' }, short: { time: 5*60, label: 'Kısa Mola', color: '#22c55e' }, long: { time: 15*60, label: 'Uzun Mola', color: '#3b82f6' } };
let current = 'pomodoro', total = modes.pomodoro.time, remaining = total, running = false, interval = null, sessions = 0;
const circumference = 2 * Math.PI * 110;
function setMode(mode, btn) {
  current = mode;
  document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  btn.classList.add('active');
  total = modes[mode].time;
  remaining = total;
  running = false;
  clearInterval(interval);
  document.getElementById('start-btn').textContent = 'Başla';
  updateDisplay();
  const color = modes[mode].color;
  document.getElementById('ring').style.stroke = color;
  document.querySelector('.start-btn').style.background = color;
  document.querySelector('.start-btn').style.boxShadow = `0 8px 24px ${color}55`;
}
function toggle() {
  if (running) { clearInterval(interval); running = false; document.getElementById('start-btn').textContent = 'Devam'; }
  else { running = true; document.getElementById('start-btn').textContent = 'Durdur'; interval = setInterval(tick, 1000); }
}
function tick() {
  remaining--;
  if (remaining <= 0) {
    clearInterval(interval); running = false;
    if (current === 'pomodoro') { sessions = Math.min(sessions + 1, 4); document.getElementById('session-count').textContent = sessions; updateDots(); }
    document.getElementById('start-btn').textContent = 'Başla';
    remaining = 0;
  }
  updateDisplay();
}
function reset() { clearInterval(interval); running = false; remaining = total; document.getElementById('start-btn').textContent = 'Başla'; updateDisplay(); }
function skip() { clearInterval(interval); running = false; remaining = 0; updateDisplay(); }
function updateDisplay() {
  const m = Math.floor(remaining / 60).toString().padStart(2,'0');
  const s = (remaining % 60).toString().padStart(2,'0');
  document.getElementById('time').textContent = m + ':' + s;
  document.getElementById('label').textContent = modes[current].label;
  const pct = remaining / total;
  document.getElementById('ring').style.strokeDashoffset = circumference * (1 - pct);
  document.getElementById('ring').style.strokeDasharray = circumference;
}
function updateDots() {
  const dots = document.getElementById('dots');
  dots.innerHTML = Array(4).fill('').map((_, i) => `<div class="dot ${i < sessions ? 'done' : ''}"></div>`).join('');
}
updateDots();
updateDisplay();
